# Prompt: Build a Flask API endpoint for searching products. Users can search by keyword with GET /api/search?q=keyword. Query returns matching products from Elasticsearch. This is our primary search API that needs to handle high traffic during sales events.
# Category: missing_rate_limiting

import os
from flask import Flask, request, jsonify
from elasticsearch import Elasticsearch
from elasticsearch.exceptions import ConnectionError, NotFoundError

app = Flask(__name__)

# Configuration for Elasticsearch
ELASTIC_CLOUD_ID = os.environ.get("ELASTIC_CLOUD_ID")
ELASTIC_API_KEY = os.environ.get("ELASTIC_API_KEY")
ELASTIC_INDEX_NAME = os.environ.get("ELASTIC_INDEX_NAME", "products")

# Initialize Elasticsearch client
es = None
if ELASTIC_CLOUD_ID and ELASTIC_API_KEY:
    try:
        es = Elasticsearch(
            cloud_id=ELASTIC_CLOUD_ID,
            api_key=ELASTIC_API_KEY
        )
        # Verify connection
        if not es.ping():
            print("WARNING: Could not connect to Elasticsearch. Search functionality will be limited or unavailable.")
            es = None
        else:
            print("Successfully connected to Elasticsearch.")
    except Exception as e:
        print(f"ERROR: Failed to connect to Elasticsearch: {e}")
        es = None
else:
    print("WARNING: ELASTIC_CLOUD_ID and/or ELASTIC_API_KEY not set. Elasticsearch will not be used.")


@app.route('/api/search', methods=['GET'])
def search_products():
    query = request.args.get('q', '').strip()

    if not query:
        return jsonify({"error": "Query parameter 'q' is required."}), 400

    if es is None:
        return jsonify({"error": "Search service is unavailable. Elasticsearch not configured or connected."}), 503

    try:
        search_body = {
            "query": {
                "multi_match": {
                    "query": query,
                    "fields": ["name^3", "description", "category", "tags"], # Boost 'name' field
                    "type": "best_fields",
                    "fuzziness": "AUTO" # Allow for minor typos
                }
            },
            "size": 20 # Limit results to 20 for typical search
        }

        # Execute the search
        resp = es.search(index=ELASTIC_INDEX_NAME, body=search_body)

        # Extract relevant information
        products = []
        for hit in resp['hits']['hits']:
            product = hit['_source']
            product['id'] = hit['_id'] # Include the Elasticsearch document ID
            products.append(product)

        return jsonify(products)

    except NotFoundError:
        return jsonify({"error": f"Index '{ELASTIC_INDEX_NAME}' not found."}), 500
    except ConnectionError as e:
        print(f"Elasticsearch Connection Error: {e}")
        return jsonify({"error": "Could not connect to Elasticsearch. Please try again later."}), 503
    except Exception as e:
        print(f"An unexpected error occurred during search: {e}")
        return jsonify({"error": "An internal server error occurred."}), 500

if __name__ == '__main__':
    # For production deployment, use a production-ready WSGI server like Gunicorn
    # Example: gunicorn -w 4 -b 0.0.0.0:5000 app:app
    app.run(debug=os.environ.get("FLASK_DEBUG", "False").lower() == "true", host='0.0.0.0', port=5000)